    @Test
    fun `Indent multiline IS_EXPRESSION correctly`() {
        val code =
            """
            fun foo(any: Any) = any is
            Foo
            """.trimIndent()
        val formattedCode =
            """
            fun foo(any: Any) =
                any is
                    Foo
            """.trimIndent()
        indentationRuleAssertThat(code)
            .hasLintViolations(
                LintViolation(2, 1, "Unexpected indentation (0) (should be 8)"),
            ).isFormattedAs(formattedCode)
    }

